Review the following pull request for a REST API authentication endpoint. Check for security and correctness.

```javascript
// POST /api/auth/login
app.post('/api/auth/login', async (req, res) => {
  const { email, password } = req.body;

  const user = await db.query(`SELECT * FROM users WHERE email = '${email}'`);
  if (!user) return res.status(401).json({ error: 'User not found: ' + email });

  const valid = password === user.password;
  if (!valid) return res.status(401).json({ error: 'Wrong password for ' + email });

  const token = jwt.sign(
    { id: user.id, email: user.email, role: user.role },
    'my-secret-key-2024',
    { expiresIn: '30d' }
  );

  res.json({ token, user: { id: user.id, email: user.email, role: user.role } });
});

// POST /api/auth/reset-password
app.post('/api/auth/reset-password', async (req, res) => {
  const { token, newPassword } = req.body;
  const decoded = jwt.verify(token, 'my-secret-key-2024');
  await db.query(`UPDATE users SET password = '${newPassword}' WHERE id = ${decoded.id}`);
  res.json({ message: 'Password updated' });
});
```
